INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-410e2224-moex-00185', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '關於特別犧牲補償之敘述，下列何者錯誤？', '["被徵收土地之所有權人於補償費發給或經合法提存前仍保有該土地之所有權", "需用土地人不於公告期滿完畢後15日內將應補償地價及其他補償費額繳交主管機關發給完竣 者，其徵收土地之核准失其效力", "某一道路範圍內之私有土地均辦理徵收，惟對於既成道路有公用地役關係者，可以命令規定繼 續使用，無須辦理徵收補償", "個人行使財產權仍應依法受社會責任及環境生態責任之限制，因此類責任使財產之利用受有合 理限制，不成立特別犧牲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00186', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '關於國家賠償之敘述，下列何者錯誤？', '["甲騎乘機車因路面不平而發生車禍，造成其車輛嚴重損害，原則上甲得向道路養護機關請求修 復其機車", "各級政府為支應可能發生之國家賠償，應依法編列預算支應", "乙向B行政機關請求國家賠償，B行政機關於乙提出請求後已逾2個月不開始協議，乙依法即 可提起國家賠償之訴", "人民向國家機關請求國家賠償，其請求權自知有損害時起，因2年間不行使而消滅，若自損害 發生時起，逾5年者亦同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00187', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-adc7838e', 'sub-generalpolice-410e2224-01', NULL, 'essay', '近年來，許多民眾要求交通部進行政策改革，以確保臺灣鐵路管理局（簡
稱台鐵）的行車安全和永續經營。相關之政策建議五花八門，包括「台
鐵企業化」、「台鐵公司化」和「台鐵民營化」等改革方向。請比較這三
項政策改革在理論意涵上的差異，並扼要評估三者之可行性和預期成
效。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "71e3e4a9a8a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共政策", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00188', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-adc7838e', 'sub-generalpolice-410e2224-01', NULL, 'essay', '何謂影響評估（impactevaluation）？如欲針對我國已實施多年的全民健
康保險政策執行影響評估，請闡述可能面對的主要挑戰為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "71e3e4a9a8a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共政策", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00189', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-adc7838e', 'sub-generalpolice-410e2224-01', NULL, 'essay', '既有文獻指出，政府預算政策的制定大致符合漸進主義模型的特色，請
說明何以政府預算政策會呈現漸進主義的特色。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "71e3e4a9a8a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共政策", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00190', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-adc7838e', 'sub-generalpolice-410e2224-01', NULL, 'essay', '政府應扮演的角色與功能為何，眾說紛紜。特別是大政府的支持者和小
政府的倡導者兩大陣營屢屢爭辯不休，難以達成共識。請針對此一議題，
闡述您的看法和評論。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "71e3e4a9a8a4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公共政策", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00191', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-de0a21a2', 'sub-generalpolice-410e2224-02', NULL, 'essay', '甲女某日獨自於戶外郊遊，行經一個陌生僻靜之處，突然見到 A男在該
地形跡鬼祟，頓時心生警覺，立即加快腳步要離開，沒想到 A卻叫住她
「不要跑」，甲聞言大驚更是用盡全力快跑，卻見A從後面追過來，甲於
是掏出隨身攜帶的防狼辣椒噴霧，朝 A的臉部噴去，造成 A的臉部皮膚
發炎及眼睛結膜炎，但事實上 A是當地地主，只是要告誡甲不要進入其
私人土地，試分析甲的行為在刑法上應如何評價。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "cc22ba360ddf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00192', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-de0a21a2', 'sub-generalpolice-410e2224-02', NULL, 'essay', '甲與其父親 A不和已久，離家租屋居住多年，某日收到醫院告知，A因
嚴重中風被送到醫院，但由於甲認為自己已與家中斷絕一切關係，此事
與他無關，並未前往醫院，而是選擇置之不理，A由於中風已達不能自
理之程度，且無其他親人，只有鄰居 B熱心協助送醫並經常前來探視，
試分析甲之行為在刑法上如何予以評價。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "cc22ba360ddf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00193', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-de0a21a2', 'sub-generalpolice-410e2224-02', NULL, 'essay', '甲接獲曾向伊購買毒品的乙的來電，要購買第三級毒品愷他命。甲以現
時手上沒貨，且最近警察查緝很緊，不願出貨為由拒絕。乙表示要出比
市場行情高三倍的價錢購買，請甲看在老客戶面子上，一定要賣他。甲
被乙說動，表示願向別人調貨。雙方約定某日當面交錢交貨。甲聯絡丙，
願意以市場行情高兩倍價錢向其調貨，甲因而順利拿到毒品。隨後，甲
依約跟乙見面交貨，旋為埋伏員警當場查獲。事實上，乙因持有毒品被
員警查獲，受員警指示要配合警方辦案，無論如何一定要將甲約出，乙
本無購買毒品之意。甲也不是第一次因毒品案被警查獲。甲被提起公訴。
審判時，甲聲請傳喚證人乙到庭對質詰問，法院迭次傳喚、拘提乙無著
落，致均未能踐行詰問乙之程序。甲以警方辦案有違法之處及乙未到庭
對質詰問為由，請求法院為無罪判決。試問法院應如何判斷甲請求之合
法性。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "cc22ba360ddf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00194', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-de0a21a2', 'sub-generalpolice-410e2224-02', NULL, 'essay', '甲因販賣毒品被警方逮捕，乙向甲購買毒品也一併被查獲。員警向甲提
示一份通訊監察錄音譯文，內載乙向甲購買毒品的通話內容。甲對該譯
文內容未表示異議。針對該譯文內容所載交易暗語，員警在譯文內加註
解釋文字，經員警詢問甲是否正確，甲也清楚交代，皆有筆錄為證。其
後，員警詢問乙時，提示一張甲的照片，要乙確認是否即為向其購買毒
品的人。乙表示確為其人，因甲乙曾數次當面毒品交易，經乙於筆錄上
簽名確認。甲被提起公訴。審判時，甲抗辯員警提示通訊監察錄音譯文，
要求伊陳述，顯有誘導詢問之實，又提示甲的照片要求乙確認，亦有誤
導乙之嫌。試問法院應如何判斷甲抗辯之合法性。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "cc22ba360ddf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0901", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL)
